		$this->debug_text("shift_acl(): Removing ACO. ($aco_key)");
		unset($acl_array['aco'][$aco_section_value][$aco_key]);
		$update = 1;
	} else {
		$this->debug_text("shift_acl(): ACO doesn't exist, can't remove it.");
	}
}

